from decimal import Decimal, InvalidOperation

def parse_monto(s):
    try:
        return Decimal(s).quantize(Decimal('0.01'))
    except (InvalidOperation, TypeError) as e:
        raise ValueError(f'monto inválido {s!r}') from e
print(parse_monto('10.5'))
try:
    parse_monto('x')
except ValueError as e:
    print('reject', e)

seen=set()
for row in [{'id':'C1'},{'id':'C1'},{'id':'C2'}]:
    if row['id'] in seen:
        print('quarantine', row, 'duplicate_id')
    else:
        seen.add(row['id']); print('clean', row)

def validate_schema(obj, required):
    missing=[k for k in required if k not in obj]
    return (not missing, missing)
print(validate_schema({'id':'C1','email':None},['id','email']))
print(validate_schema({'id':'C1'},['id','email']))

